def s(x):
    sum=0
    while x>0:
        sum=sum+x%10
        x=x//10
    return sum

def f(n):
    l=1
    r=10**9
    while l<=r:
        mid=(l+r)//2
        if mid**2+s(mid)*mid==n:
            return mid
        elif mid**2+s(mid)*mid<n:
            l=mid+1
        else:
            r=mid-1
    return -1

n=int(input())
print(f(n))
